}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "模式决策（自营 vs 加盟）: 评估资金（加盟需50-200万，自营15-80万）、课程研发能力、品牌资源；加盟路径风险低但利润分成约30-50%；inputs: 资金+经验，outputs: 商业模式决策书。"
  "选址与市场调研: 优先学校周边500米或社区商圈，核查竞对密度（3公里内同类机构数）、目标客户家庭收入水平、周边小学/初中招生规模；inputs: 模式决策，outputs: 选址分析报告+意向合同。"
  "场地改造与教室设计: 按每生3平米计算容量，配置稳定网络（百兆独享）、备用电源、每台电脑独立UPS；教室布局参照小组学习模式（4人一组）；inputs: 租约，outputs: 装修图纸+验收清单。"
  "课程体系搭建: 根据目标年龄段选定课程（Scratch/Python/机器人），采购或自研教材，制定教学进度标准；inputs: 市场调研结果，outputs: 课程目录+教材版本。"
  "师资招募与培训: 发布招聘（应届CS师范生+有编程背景的年轻人），完成岗前培训（技术+教学法+模拟授课考核），合格后上岗；参考 Code.org 教师培训框架 (evidence: [T03-S003])；inputs: 课程体系，outputs: 教师团队+培训档案。"
  "运营系统配置: 搭建学员管理系统（CRM/排课/缴费/家长通知）、准备收据发票、建立微信家长群SOP；inputs: 人员到位，outputs: 运营流程手册。"
  "首期招生: 举办免费体验课（目标50人进场，转化10-20名正式学员），配合朋友圈/小红书/社区地推；inputs: 场地+师资就绪，outputs: 首期学员名单+营收预期。"
)
declare -a FAILURE_MODES=(

)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "0-1-walkthrough"
fi
